```cpp
#include <iostream>

class SensorData {
public:
    SensorData(int val) : value(val) {}
    int getValue() { return value; }
private:
    int value;
};

void processSensor(int rawValue) {
    SensorData* data = new SensorData(rawValue);
    // do some math with data
    std::cout << "Processing: " << data->getValue() << std::endl;

    if (rawValue < 0) {
        return; // error state
    }

    delete data;
}

int main() {
    for (int i = 0; i < 100; ++i) {
        processSensor(i - 5); 
    }
    return 0;
}
